import { Injectable, NgZone } from '@angular/core';
import { Observable, Subject, BehaviorSubject } from 'rxjs';
import RecordRTC from 'recordrtc';

// Extend the Window interface to include speech recognition
declare global {
  interface Window {
    SpeechRecognition: any;
    webkitSpeechRecognition: any;
  }
}

interface AudioState {
  isRecording: boolean;
  isProcessing: boolean;
  transcript: string;
  confidence: number;
}

@Injectable({ providedIn: 'root' })
export class AudioService {
  private mediaRecorder: RecordRTC | null = null;
  private recognition: any = null;
  private synthesis: SpeechSynthesis;

  // Enhanced state management
  private audioStateSubject = new BehaviorSubject<AudioState>({
    isRecording: false,
    isProcessing: false,
    transcript: '',
    confidence: 0
  });

  private finalTranscriptSubject = new Subject<string>();
  private partialTranscriptSubject = new Subject<string>();
  private errorSubject = new Subject<string>();

  audioState$ = this.audioStateSubject.asObservable();
  finalTranscript$ = this.finalTranscriptSubject.asObservable();
  partialTranscript$ = this.partialTranscriptSubject.asObservable();
  error$ = this.errorSubject.asObservable();

  constructor(private zone: NgZone) {
    this.synthesis = window.speechSynthesis;
    this.initializeSpeechRecognition();
  }

  private initializeSpeechRecognition() {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      this.recognition = new SpeechRecognition();

      // Configuration pour une reconnaissance continue
      this.recognition.continuous = true;
      this.recognition.interimResults = true;
      this.recognition.lang = 'fr-FR';
      this.recognition.maxAlternatives = 1;

      this.recognition.onstart = () => {
        this.zone.run(() => {
          const currentState = this.audioStateSubject.value;
          this.audioStateSubject.next({
            ...currentState,
            isRecording: true,
            isProcessing: false
          });
        });
      };

      this.recognition.onresult = (event: any) => {
        let finalTranscript = '';
        let interimTranscript = '';
        let maxConfidence = 0;

        for (let i = event.resultIndex; i < event.results.length; i++) {
          const result = event.results[i];
          const transcript = result[0].transcript;
          const confidence = result[0].confidence || 0;

          if (result.isFinal) {
            finalTranscript += transcript;
            maxConfidence = Math.max(maxConfidence, confidence);
          } else {
            interimTranscript += transcript;
          }
        }

        this.zone.run(() => {
          const currentState = this.audioStateSubject.value;

          // Update partial transcript
          if (interimTranscript) {
            this.partialTranscriptSubject.next(interimTranscript);
          }

          // Update state with partial transcript
          this.audioStateSubject.next({
            ...currentState,
            transcript: currentState.transcript + finalTranscript,
            confidence: maxConfidence
          });

          // Emit final transcript
          if (finalTranscript) {
            this.finalTranscriptSubject.next(finalTranscript);
          }
        });
      };

      this.recognition.onerror = (event: any) => {
        console.error('Speech recognition error:', event.error);
        this.zone.run(() => {
          this.errorSubject.next(`Erreur de reconnaissance: ${event.error}`);
          const currentState = this.audioStateSubject.value;
          this.audioStateSubject.next({
            ...currentState,
            isRecording: false,
            isProcessing: false
          });
        });
      };

      this.recognition.onend = () => {
        this.zone.run(() => {
          const currentState = this.audioStateSubject.value;
          this.audioStateSubject.next({
            ...currentState,
            isRecording: false,
            isProcessing: false
          });
        });
      };
    }
  }

  async startContinuousRecording(): Promise<void> {
    try {
      const currentState = this.audioStateSubject.value;
      if (currentState.isRecording) {
        return;
      }

      if (this.recognition) {
        // Reset transcript for new session
        this.audioStateSubject.next({
          ...currentState,
          transcript: '',
          confidence: 0
        });

        this.recognition.start();
      } else {
        throw new Error('La reconnaissance vocale n\'est pas supportée dans ce navigateur');
      }
    } catch (error) {
      console.error('Error starting recording:', error);
      this.zone.run(() => {
        this.errorSubject.next('Impossible d\'accéder au microphone');
      });
      throw error;
    }
  }

  stopRecording(): void {
    if (this.recognition) {
      this.recognition.stop();
    }
  }

  // Enhanced text-to-speech with auto-detection of language
  speak(text: string, options: { lang?: string; rate?: number; pitch?: number } = {}): Promise<void> {
    return new Promise((resolve, reject) => {
      if (this.synthesis.speaking) {
        this.synthesis.cancel();
      }

      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = options.lang || 'fr-FR';
      utterance.rate = options.rate || 0.9;
      utterance.pitch = options.pitch || 1;
      utterance.volume = 1;

      utterance.onend = () => {
        this.zone.run(() => resolve());
      };

      utterance.onerror = (event) => {
        this.zone.run(() => reject(event.error));
      };

      this.synthesis.speak(utterance);
    });
  }

  stopSpeaking(): void {
    if (this.synthesis.speaking) {
      this.synthesis.cancel();
    }
  }

  isSpeechRecognitionSupported(): boolean {
    return 'webkitSpeechRecognition' in window || 'SpeechRecognition' in window;
  }

  isSpeechSynthesisSupported(): boolean {
    return 'speechSynthesis' in window;
  }

  // Get available voices for better language selection
  getAvailableVoices(): SpeechSynthesisVoice[] {
    return this.synthesis.getVoices();
  }

  // Auto-detect language from text (simple implementation)
  private detectLanguage(text: string): string {
    // Simple heuristic: if contains French characters, use French
    const frenchChars = /[àâäéèêëïîôöùûüÿç]/i;
    return frenchChars.test(text) ? 'fr-FR' : 'en-US';
  }

  // Smart speak with auto-language detection
  speakSmart(text: string): Promise<void> {
    const lang = this.detectLanguage(text);
    return this.speak(text, { lang });
  }

  // Clear current transcript
  clearTranscript(): void {
    const currentState = this.audioStateSubject.value;
    this.audioStateSubject.next({
      ...currentState,
      transcript: '',
      confidence: 0
    });
  }

  // Get current state
  getCurrentState(): AudioState {
    return this.audioStateSubject.value;
  }
}
